import jui from"jui";const{toast:toast,modal:modal,postJson:postJson,restUrl:restUrl,t:t,on:on}=jui,langs={zh:{Login:"登录",username:"用户名",password:"密码",Cancel:"取消","Enter Username Please":"请输入用户名","Enter Password Please":"请输入密码","Username Required":"用户名不能为空","Password Required":"密码不能为空","Login Success":"登录成功"}},ts=e=>t(e,langs),__loginModal=new modal({title:ts("Login"),confirmText:ts("Login"),cancelText:ts("Cancel"),escClose:!0,fields:[{label:ts("username"),type:"text",name:"username",id:"username",placeholder:ts("Enter Username Please"),required:!0},{label:ts("password"),type:"password",name:"password",id:"password",placeholder:ts("Enter Password Please"),required:!0}],onSubmit:e=>{e.username.trim()?(e.password.trim()||toast.error(ts("Password Required")),postJson(restUrl+"/api/v1/auth/login",{username:e.username,password:e.password}).then(e=>{200===e.code?(toast.success(ts("Login Success")),setTimeout(()=>{window.location.href="/"},1e3)):toast.error(e.message)})):toast.error(ts("Username Required"))}});on(document.body,"click",e=>{e.target.closest('[data-action="login"]')&&__loginModal.show()});